        else -> SORT_BY_DATE_CREATED
    }

    if (sorting != SORT_BY_CUSTOM && binding.sortingDialogRadioOrder.checkedRadioButtonId == R.id.sorting_dialog_radio_descending) {
        sorting = sorting or SORT_DESCENDING
    }

